                            animation: lf-orbit-rotate 40s linear infinite;
                        }

                        .lf-slot {
                            position: absolute;
                            top: 50%;
                            left: 50%;
                        }

                        /* =========================
   COIN STRUCTURE
========================= */

                        /* Mantém a moeda "em pé" */
                        .lf-coin-rotate-wrapper {
                            animation: lf-orbit-rotate-rev 40s linear infinite;
                        }

                        /* Flutuação */
                        .lf-coin-float-wrapper {
                            width: 120px;
                            height: 120px;
                            animation: lf-float 6s ease-in-out infinite;
                        }

                        .lf-coin-float-wrapper img {
                            width: 100%;
                            display: block;

                            /* SOMBRA SUTIL PREMIUM */
                            filter: drop-shadow(0 6px 14px rgba(11, 31, 42, 0.18));
                        }

                        /* =========================
   POSIÇÕES (DESKTOP)
========================= */
                        .slot-1 {
                            transform: translate(-50%, -50%) rotate(0deg) translate(205px) rotate(0deg);
                        }

                        .slot-2 {
                            transform: translate(-50%, -50%) rotate(40deg) translate(205px) rotate(-40deg);
                        }

                        .slot-3 {
                            transform: translate(-50%, -50%) rotate(80deg) translate(205px) rotate(-80deg);
                        }

                        .slot-4 {
                            transform: translate(-50%, -50%) rotate(120deg) translate(205px) rotate(-120deg);
                        }

                        .slot-5 {
                            transform: translate(-50%, -50%) rotate(160deg) translate(205px) rotate(-160deg);
                        }

                        .slot-6 {
                            transform: translate(-50%, -50%) rotate(200deg) translate(205px) rotate(-200deg);
                        }

                        .slot-7 {
                            transform: translate(-50%, -50%) rotate(240deg) translate(205px) rotate(-240deg);
                        }

                        .slot-8 {
                            transform: translate(-50%, -50%) rotate(280deg) translate(205px) rotate(-280deg);
                        }

                        .slot-9 {
                            transform: translate(-50%, -50%) rotate(320deg) translate(205px) rotate(-320deg);
                        }

                        /* =========================
   ANIMATIONS
========================= */
                        @keyframes lf-orbit-rotate {
                            from {
                                transform: rotate(0deg);
                            }

                            to {
                                transform: rotate(360deg);
                            }
                        }

                        @keyframes lf-orbit-rotate-rev {
                            from {
                                transform: rotate(0deg);
                            }

                            to {
                                transform: rotate(-360deg);
                            }
                        }

                        @keyframes lf-float {

                            0%,
                            100% {
                                transform: translateY(0) rotate(-2deg);
                            }

                            50% {
                                transform: translateY(-12px) rotate(3deg);
                            }
                        }

                        /* Delays no float (organicidade) */
                        .slot-1 .lf-coin-float-wrapper {
                            animation-delay: 0s;
                        }

                        .slot-2 .lf-coin-float-wrapper {
                            animation-delay: 0.6s;
                        }

                        .slot-3 .lf-coin-float-wrapper {
                            animation-delay: 1.1s;
                        }

                        .slot-4 .lf-coin-float-wrapper {
                            animation-delay: 0.3s;
                        }

                        .slot-5 .lf-coin-float-wrapper {
                            animation-delay: 0.9s;
                        }

                        .slot-6 .lf-coin-float-wrapper {
                            animation-delay: 1.4s;
                        }

                        .slot-7 .lf-coin-float-wrapper {
                            animation-delay: 0.5s;
                        }

                        .slot-8 .lf-coin-float-wrapper {
                            animation-delay: 1.2s;
                        }

                        .slot-9 .lf-coin-float-wrapper {
                            animation-delay: 0.8s;
                        }

                        /* =========================
   MOBILE
========================= */
                        @media (max-width: 768px) {
                            .lf-orbit-wrapper {
                                width: 340px;
                                height: 340px;
                            }

                            .lf-coin-float-wrapper {
                                width: 70px;
                                height: 70px;
                            }

                            .slot-1 {
