                            <script>
                                const cards = document.querySelectorAll('.glass-card');

                                cards.forEach(card => {
                                    card.addEventListener('mouseenter', () => {
                                        cards.forEach(other => {
                                            if (other !== card) {
                                                gsap.to(other, {
                                                    x: other.getAttribute('data-dx'),
                                                    y: other.getAttribute('data-dy'),
                                                    scale: 0.85,
                                                    opacity: 0.4,
                                                    filter: "blur(4px)",
                                                    duration: 0.8,
                                                    ease: "power2.out"
                                                });
                                            } else {
                                                gsap.to(card, {
                                                    scale: 1.25,
                                                    z: 100,
                                                    opacity: 1,
                                                    filter: "blur(0px)",
                                                    duration: 0.8,
                                                    ease: "power2.out"
                                                });
                                            }
                                        });
                                    });

                                    card.addEventListener('mouseleave', () => {
                                        gsap.to(cards, {
                                            x: 0,
                                            y: 0,
                                            scale: 1,
                                            z: 0,
                                            opacity: 1,
                                            filter: "blur(0px)",
                                            duration: 0.8,
                                            ease: "power2.inOut"
                                        });
                                    });
                                });
                            </script>
