<style>
    .lf-telegram-container {
        position: fixed;
        bottom: 30px;
        right: 30px;
        display: flex;
        align-items: center;
        z-index: 9999;
    }

    .lf-telegram-float {
        width: 60px;
        height: 60px;
        background: linear-gradient(180deg, #3EE9F0 0%, #22E0E8 100%);
        border-radius: 50%;
        display: flex;
        align-items: center;
        justify-content: center;
        box-shadow: 0 10px 25px rgba(34, 224, 232, 0.4);
        transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    }

    /* Tooltip Styling */
    .lf-tg-tooltip {
        position: absolute;
        right: 80px;
        background: #063142;
        color: #22E0E8;
        padding: 8px 16px;
        border-radius: 8px;
        font-size: 11px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 0.1em;
        white-space: nowrap;
        opacity: 0;
        visibility: hidden;
        transform: translateX(10px);
        transition: all 0.3s ease;
        border: 1px solid rgba(34, 224, 232, 0.2);
    }

    .lf-telegram-container:hover .lf-tg-tooltip {
        opacity: 1;
        visibility: visible;
        transform: translateX(0);
    }

    .lf-telegram-float:hover {
        transform: scale(1.1);
        box-shadow: 0 15px 30px rgba(34, 224, 232, 0.6);
    }

    /* Pulse animation logic */
    .lf-tg-pulse {
        position: absolute;
        width: 100%;
        height: 100%;
        background: #22E0E8;
        border-radius: 50%;
        z-index: -1;
        opacity: 0.7;
        animation: lf-tg-ping 2s cubic-bezier(0, 0, 0.2, 1) infinite;
    }

    @keyframes lf-tg-ping {
        75%, 100% {
            transform: scale(1.6);
            opacity: 0;
        }
    }

    @media (max-width: 768px) {
        .lf-telegram-container { bottom: 20px; right: 20px; }
        .lf-telegram-float { width: 50px; height: 50px; }
        .lf-tg-tooltip { display: none; } /* Hide tooltip on mobile to save space */
    }
</style>
