    <script>
        window.addEventListener("load", function () {

            const toggle = document.querySelector(".mobile-menu-icon");
            const menu = document.querySelector(".elementor-nav-menu--dropdown");

            if (!toggle || !menu) return;

            /* create overlay */
            const overlay = document.createElement("div");
            overlay.className = "menu-overlay";
            document.body.appendChild(overlay);

            function openMenu() {
                menu.classList.add("active-menu");
                overlay.classList.add("show");
                document.body.classList.add("menu-open");
            }

            function closeMenu() {
                menu.classList.remove("active-menu");
                overlay.classList.remove("show");
                document.body.classList.remove("menu-open");
            }

            /* TOGGLE CLICK (important fix) */
            toggle.addEventListener("click", function (e) {
                e.preventDefault();

                if (menu.classList.contains("active-menu")) {
                    closeMenu();
                } else {
                    openMenu();
                }
            });

            /* close when clicking outside */
            overlay.addEventListener("click", closeMenu);

            /* close when clicking menu link (event delegation — Elementor safe) */
            menu.addEventListener("click", function (e) {
                if (e.target.closest("a")) {
                    closeMenu();
                }
            });

        });
    </script>





